React Native
Use the React Native hook and components for mobile apps.
Installation
npm install @semaphore-pay/client

Setup
import { useSemaphorePay } from &#039;@semaphore-pay/client/react-native&#039;;

function App() {
  const {
    ready,
    customerId,
    subscribed,
    subscriptionStatus,
    error,
    subscribe,
    check,
    report,
    client,
  } = useSemaphorePay({
    baseUrl: &#039;https://your-api.example.com&#039;,
    apiKey: &#039;pk_your_key&#039;,
    collectionId: &#039;col_abc123&#039;,
    planId: &#039;plan_pro_monthly&#039;,
    userId: &#039;user_123&#039;,
    userEmail: &#039;user@example.com&#039;,
    userName: &#039;John Doe&#039;,
    autoSubscribe: true,
  });

  if (error) return &lt;Text&gt;Error: {error}&lt;/Text&gt;;
  if (!ready) return &lt;ActivityIndicator /&gt;;

  if (subscribed) return &lt;Dashboard /&gt;;

  return (
    &lt;View&gt;
      &lt;Text&gt;Setting up subscription...&lt;/Text&gt;
    &lt;/View&gt;
  );
}

